#include <stdio.h>
#include <math.h>
typedef struct{float x,y,z;}V;
typedef struct{V o,d;}R;
typedef struct{float t;V p,n;int h;}H;
V A(V a,V b){return(V){a.x+b.x,a.y+b.y,a.z+b.z};}
V S(V a,V b){return(V){a.x-b.x,a.y-b.y,a.z-b.z};}
V M(V a,float s){return(V){a.x*s,a.y*s,a.z*s};}
float D(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}
V N(V a){return M(a,1/sqrtf(D(a,a)));}
V at(R r,float t){return A(r.o,M(r.d,t));}
R ray(V o,V d){return(R){o,N(d)};}
H sph(V c,float rr,R r){
 V oc=S(r.o,c);float a=D(r.d,r.d),b=2*D(oc,r.d),cc=D(oc,oc)-rr*rr,di=b*b-4*a*cc,t;H h={0};
 if(di<0)return h;t=(-b-sqrt(di))/(2*a);if(t<.001){t=(-b+sqrt(di))/(2*a);if(t<.001)return h;}
 h.h=1;h.t=t;h.p=at(r,t);h.n=N(S(h.p,c));return h;
}
H pl(float y,R r){
 H h={0};if(fabsf(r.d.y)<.0001)return h;float t=(y-r.o.y)/r.d.y;if(t<.001)return h;
 h.h=1;h.t=t;h.p=at(r,t);h.n=(V){0,1,0};return h;
}
V sky(R r){float t=.5*(r.d.y+1);return A(M((V){1,1,1},1-t),M((V){.5,.7,1},t));}
int sh(V p,V l,V c){return sph(c,1,ray(p,l)).h;}
V tr(R r,V c,V l){
 H a=sph(c,1,r),b=pl(-1.5,r),h;int sp=0;if(a.h&&(!b.h||a.t<b.t))h=a,sp=1;else if(b.h)h=b;else return sky(r);
 float s=fmaxf(D(h.n,l),0);if(sh(A(h.p,M(h.n,.001)),l,c))s=0;s=.2+.8*s;
 if(sp)return M((V){1,.2,.2},s);int k=((int)(floor(h.p.x)+floor(h.p.z))&1)==0;return M(k?(V){.9,.9,.9}:(V){.4,.4,.4},s);
}
int main(){
 int W=2400,Hh=1800;FILE*f=fopen("reconstructed.ppm","w");fprintf(f,"P3\n%d %d\n255\n",W,Hh);
 V o={0,0,0},hz={2*(float)W/Hh,0,0},vt={0,2,0},ll=S(S(S(o,M(hz,.5)),M(vt,.5)),(V){0,0,1}),c={0,-.5,-5},l=N((V){1,1,-1});
 for(int y=0;y<Hh;y++)for(int x=0;x<W;x++){float u=(float)x/(W-1),v=(float)y/(Hh-1);V d=A(ll,A(M(hz,u),M(vt,1-v))),q=tr(ray(o,d),c,l);int r=fmin(fmax(q.x,0),1)*255.99,g=fmin(fmax(q.y,0),1)*255.99,b=fmin(fmax(q.z,0),1)*255.99;fprintf(f,"%d %d %d\n",r,g,b);}
 fclose(f);return 0;
}

